INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-01127', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某世代研究探討成人飲食符合地球健康飲食（planetaryhealthdiet）程度與追蹤9年糖尿病風 險之相關性。結果發現，在校正干擾因子之後，基線期飲食最符合地球健康飲食建議程度的 五分位組與最不符合的五分位組相比，發生糖尿病之相對風險為0.71（95%CI=0.56-0.89）。 進一步校正基線期身體質量指數之後，相對風險為0.95（95%CI=0.75-1.21）。根據以上描述， 下列敘述何者錯誤？', '["身體質量指數與糖尿病風險無關", "若身體質量指數是中介因子，遵循地球健康飲食應有益於降低糖尿病風險", "遵循地球健康飲食可能與身體質量指數有關", "身體質量指數若不是干擾因子，就是中介因子"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01128', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '兩位醫師（A,B）被要求獨立將100張胸部X光片歸類為正常（Normal）或不正常（Abnormal）： 兩位醫師皆判定為不正常有28片；A醫師判定為正常但B醫師判定為不正常有18片；A醫 師判定為不正常但B醫師判定為正常有12片；兩位醫師皆判定為正常有42片，Kappa值是 下列何者？', '["0.70", "0.51", "0.39", "0.20"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01129', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某世代研究調查某國6萬多民成年人，發現當中有高達90%的日常飲食未達一日五次蔬果。 串聯該族群8年內的死亡檔數據顯示，校正干擾因素後，未達一日五次蔬果者的死亡率是一 日五次蔬果者的1.2倍。根據上述數據，一日五次蔬果的族群可歸因風險百分比估計值為何？', '["15%", "20%", "0.15%", "10%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01130', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '根據圖示中的DAG，下列論點何者正確？', '["若要探討體能活動習慣與糖尿病之間的因果相關，應該控制含糖飲料習慣，因為它會造成 干擾", "若要探討體能活動習慣與糖尿病之間的因果相關，不該控制含糖飲料習慣，因為它是中介 因子", "「未測量因子」是體能活動習慣與糖尿病的干擾因素", "「未測量因子」是含糖飲料習慣與糖尿病的干擾因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01131', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '篩檢工具A施用於100人的社區來篩檢疾病X：已知有X病的人，其中16人篩檢陽性，6人 陰性；沒病的人中，其中10人篩檢陽性，下列何者錯誤？', '["敏感度=61.54%", "特異度=87.18%", "陰性預測值=91.89%", "若同一個篩檢工具透過改變切點來提高敏感度，則該篩檢工具特異度降低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01132', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '比較各國所報告的貧血盛行率，下列何者若在研究間不一致，較不影響國際比較的推論效度？', '["貧血測量方法", "納入排除條件", "樣本數大小", "研究族群的年齡分布"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01133', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '適合早期偵測的癌症篩檢計畫的條件，下列何者不適合？', '["大眾接受度高", "該疾病在族群中的盛行率很低，很罕見", "符合成本效益，利益大於風險", "存在有效的介入治療以改變疾病自然史"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01134', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '早期偵測的癌症篩檢計畫伴隨而來的偏差會讓篩檢計畫看似有效或比實際狀況更有效，下列 何者不是？', '["前導期偏差（leadtimebias）", "自然病史長短（lengthbias）", "選擇性偏差（selectionbias）", "回憶偏差（recallbias）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01135', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究設計交叉試驗（crossovertrial）比較攝取植物性人造肉（以下簡稱植物組）與動物性肉 類（以下簡稱動物組）對健康指標的影響。在各為期8週的試驗階段中，受試者每日需攝取 至少2份指定肉類（植物組或動物組），同時盡可能保持其他飲食內容一致。結果顯示受試者 在植物組期間的低密度脂蛋白膽固醇與體重均顯著較動物組期間來得低。根據描述，下列說 法何者錯誤？', '["此研究不需要隨機分派", "此研究是比較受試者在二介入期之間的健康指標變化之差異", "此研究需規劃wash-out時間", "數據不需要校正干擾因子"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01136', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某社區健康服務中心比較體能介入計畫參與者的肌肉量，在全程參與16週前後，肌肉量平均 有統計顯著提升0.25kg的現象。根據這個觀察，比較下列四個評論，何者最不影響推論效度？', '["性別與年齡的干擾因素必須校正", "需確認肌肉測量的方法是否一致", "統計顯著性應用pairedttest檢驗", "需有控制組比較才能推論該體能介入計畫是否有效提升肌肉量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
